INSERT INTO zones (city_id, zone_code, zone_code_slug, zone_name, description, max_height_ft, far, min_lot_size_sqft, max_impervious_cover_pct, setback_front_ft, setback_rear_ft, setback_side_ft, parking_requirement) VALUES ((SELECT id FROM cities WHERE slug = 'miami'), 'T3-R', 't3-r', 'Sub-Urban Transect Zone - Restricted', 'Low-density areas, primarily comprised of single-family residential units with relatively deep setbacks.', 25, NULL, 5000, 75, 20, 20, 5, 'Minimum of 1.5 parking spaces per principal dwelling unit; tandem parking encouraged.') ON CONFLICT (city_id, zone_code_slug) DO UPDATE SET zone_name = excluded.zone_name, description = excluded.description, max_height_ft = excluded.max_height_ft, far = excluded.far, min_lot_size_sqft = excluded.min_lot_size_sqft, max_impervious_cover_pct = excluded.max_impervious_cover_pct, setback_front_ft = excluded.setback_front_ft, setback_rear_ft = excluded.setback_rear_ft, setback_side_ft = excluded.setback_side_ft, parking_requirement = excluded.parking_requirement;
INSERT INTO zone_permitted_uses (zone_id, permitted_use_id) SELECT z.id, pu.id FROM zones z, permitted_uses pu WHERE z.zone_code_slug = 't3-r' AND z.city_id = (SELECT id FROM cities WHERE slug = 'miami') AND pu.name IN ('Single Family Residence') ON CONFLICT DO NOTHING;
